package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setLongSerializationPolicy_shouldSetAndReturnThis() throws Exception {
    // Arrange
    LongSerializationPolicy policy = LongSerializationPolicy.STRING;

    // Act
    GsonBuilder returned = gsonBuilder.setLongSerializationPolicy(policy);

    // Assert
    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("longSerializationPolicy");
    field.setAccessible(true);
    LongSerializationPolicy actualPolicy = (LongSerializationPolicy) field.get(gsonBuilder);
    assertSame(policy, actualPolicy);
  }

  @Test
  void setLongSerializationPolicy_shouldThrowNullPointerException_whenNullPassed() {
    // Arrange
    LongSerializationPolicy policy = null;

    // Act & Assert
    NullPointerException exception = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setLongSerializationPolicy(policy);
    });
    assertNull(exception.getMessage(), "Expected NullPointerException with null message due to null argument");
  }

}
